import React, { useState, useEffect } from "react"
import QRCode from "qrcode"
import jsPDF from 'jspdf'
import Tesseract from 'tesseract.js'

const C = {
  bg: "#07111F", surface: "#0D1F35", card: "#0F2440", border: "#1A3557",
  border2: "#1E4068", accent: "#1D6FEB", accentL: "#3B8BF5", teal: "#0CB8A0",
  gold: "#E9A826", success: "#0EA874", danger: "#E53E3E", warn: "#E9A826",
  text: "#E8EFF8", muted: "#5A7A9E", muted2: "#3D5A78", white: "#FFFFFF",
}

const s = {
  page: { minHeight: "100vh", background: `radial-gradient(ellipse at 20% 0%, #0D2A4A 0%, #07111F 60%)`, display: "flex", alignItems: "center", justifyContent: "center", padding: "1rem", fontFamily: "'Inter', 'Segoe UI', sans-serif" },
  card: (w=420) => ({ width: w, maxWidth: "100%", background: C.card, border: `1px solid ${C.border2}`, borderRadius: 20, padding: "2.25rem 2rem", boxShadow: "0 32px 80px rgba(0,0,0,0.6)" }),
  inp: { width: "100%", padding: "11px 14px", borderRadius: 10, border: `1px solid ${C.border2}`, background: "#071828", color: C.text, fontSize: 14, boxSizing: "border-box", outline: "none" },
  btn: (bg, mt=12) => ({ width: "100%", padding: "12px 20px", borderRadius: 10, border: "none", background: bg, color: C.white, fontSize: 14, fontWeight: 600, cursor: "pointer", marginTop: mt }),
  label: { color: C.muted, fontSize: 12, display: "block", marginBottom: 6, fontWeight: 500 },
  badge: (bg, color) => ({ background: bg, color, padding: "3px 11px", borderRadius: 999, fontSize: 11, fontWeight: 600 }),
  sep: { borderTop: `1px solid ${C.border}`, margin: "1.25rem 0" },
}

function Field({ label, children }) { return ( <div style={{ marginBottom: "1.1rem" }}><label style={s.label}>{label}</label>{children}</div> ) }
function Toast({ msg, type }) { if (!msg) return null; return ( <div style={{ position: "fixed", top: 20, right: 20, zIndex: 9999, background: type === "error" ? "#3D0A0A" : "#052E1A", border: `1px solid ${type === "error" ? C.danger : C.success}`, color: C.text, padding: "12px 18px", borderRadius: 10, fontSize: 13, fontWeight: 500, boxShadow: "0 8px 24px rgba(0,0,0,0.4)" }}>{type === "error" ? "❌" : "✅"} {msg}</div> ) }
function Steps({ current }) { const steps = ["Login", "OTP Verify", "Personal Info", "Documents", "Payment", "Status"]; return ( <div style={{ display: "flex", alignItems: "center", justifyContent: "center", marginBottom: "2rem" }}>{steps.map((name, i) => { const done = i < current; const active = i === current; return ( <div key={i} style={{ display: "flex", alignItems: "center" }}><div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}><div style={{ width: 28, height: 28, borderRadius: "50%", background: done ? C.success : active ? C.accent : C.border2, border: `2px solid ${done ? C.success : active ? C.accentL : C.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 700, color: C.white }}>{done ? "✓" : i + 1}</div><span style={{ fontSize: 10, color: active ? C.accentL : done ? C.success : C.muted }}>{name}</span></div>{i < steps.length - 1 && <div style={{ width: 32, height: 2, background: done ? C.success : C.border, marginBottom: 14 }} />}</div> ) })}</div> ) }

function QRCodeDisplay({ data, size = 150, onCopyHash }) {
  const [qrUrl, setQrUrl] = useState(null)
  useEffect(() => { if (data && data.hash) { const qrString = `${data.studentName}\nCNIC: ${data.cnic}\nHash: ${data.hash}\n${data.degreeType}\nIqra University`; QRCode.toDataURL(qrString, { width: size, margin: 1 }, (err, url) => { if (!err) setQrUrl(url) }) } }, [data, size])
  if (!qrUrl) return <div style={{ width: size, height: size, background: "#1a1a2e", borderRadius: 12, display: "flex", alignItems: "center", justifyContent: "center" }}>Loading...</div>
  return (
    <div style={{ textAlign: "center" }}>
      <img src={qrUrl} alt="QR Code" style={{ width: size, height: size, background: "white", borderRadius: 12, padding: 10 }} />
      {onCopyHash && (
        <button onClick={onCopyHash} style={{ marginTop: 10, background: C.accent, color: "white", border: "none", padding: "5px 12px", borderRadius: 5, cursor: "pointer", fontSize: 11 }}>
          📋 Copy Hash
        </button>
      )}
    </div>
  )
}

