      if (expiry) {
        setCnicExpiry(expiry);
        const [d, m, y] = expiry.split('/');
        const expiryDate = new Date(parseInt(y), parseInt(m) - 1, parseInt(d));
        const isExpired = expiryDate < new Date();
        setCnicExpired(isExpired);
        console.log("Extracted CNIC Expiry:", expiry, "Expired:", isExpired);
      }
      
      setOcrStatus("✅ OCR Complete!");
